mapper.select:
SELECT er.id, er.user_id as userId, er.user_name as userName, er.product_id as productId, er.product_name as productName, er.product_image as productImage, er.points, er.phone, er.status, er.exchange_time as exchangeTime FROM exchange_record er WHERE 1=1
AND er.user_id = #{userId}
AND er.status = #{status}
AND er.product_name LIKE CONCAT('%', #{productName}, '%')
AND er.phone LIKE CONCAT('%', #{phone}, '%')
ORDER BY er.exchange_time DESC
